   143  func (s *Signature) Calculate(ctx context.Context, src plugins.PluginSource, plugin plugins.FoundPlugin) (plugins.Signature, error) {
   144          if defaultSignature, exists := src.DefaultSignature(ctx, plugin.JSONData.ID); exists {
   145                  return defaultSignature, nil
   146          }
   147
   148          manifest, err := s.ReadPluginManifestFromFS(ctx, plugin.FS)
   149          switch {
   150          case errors.Is(err, ErrSignatureTypeUnsigned):
   151                  s.log.Warn("Plugin is unsigned", "id", plugin.JSONData.ID, "err", err)
   152                  return plugins.Signature{
   153                          Status: plugins.SignatureStatusUnsigned,
   154                  }, nil
   155          case err != nil:
   156                  s.log.Warn("Plugin signature is invalid", "id", plugin.JSONData.ID, "err", err)
   157                  return plugins.Signature{
   158                          Status: plugins.SignatureStatusInvalid,
   159                  }, nil
   160          }
   161
   162          if !manifest.IsV2() {
   163                  return plugins.Signature{
   164                          Status: plugins.SignatureStatusInvalid,
   165                  }, nil
   166          }
   167
   168          fsFiles, err := plugin.FS.Files()
   169          if err != nil {
   170                  return plugins.Signature{}, fmt.Errorf("files: %w", err)
   171          }
   172          if len(fsFiles) == 0 {
   173                  s.log.Warn("No plugin file information in directory", "pluginId", plugin.JSONData.ID)
   174                  return plugins.Signature{
   175                          Status: plugins.SignatureStatusInvalid,
   176                  }, nil
   177          }
   178
   179          // Make sure the versions all match
   180          if manifest.Plugin != plugin.JSONData.ID || manifest.Version != plugin.JSONData.Info.Version {
   181                  s.log.Debug("Plugin signature invalid because ID or Version mismatch", "pluginId", plugin.JSONData.ID, "manifestPluginId", manifest.Plugin, "pluginVersion", plugin.JSONData.Info.Version, "manifestPluginVersion", manifest.Version)
   182                  return plugins.Signature{
   183                          Status: plugins.SignatureStatusModified,
   184                  }, nil
   185          }
   186
   187          // Validate that plugin is running within defined root URLs
   188          if len(manifest.RootURLs) > 0 {
   189                  if match, err := urlMatch(manifest.RootURLs, s.cfg.GrafanaAppURL, manifest.SignatureType); err != nil {
   190                          s.log.Warn("Could not verify if root URLs match", "plugin", plugin.JSONData.ID, "rootUrls", manifest.RootURLs)
   191                          return plugins.Signature{}, err
   192                  } else if !match {
   193                          s.log.Warn("Could not find root URL that matches running application URL", "plugin", plugin.JSONData.ID,
   194                                  "appUrl", s.cfg.GrafanaAppURL, "rootUrls", manifest.RootURLs)
   195                          return plugins.Signature{
   196                                  Status: plugins.SignatureStatusInvalid,
   197                          }, nil
   198                  }
   199          }
   200
   201          manifestFiles := make(map[string]struct{}, len(manifest.Files))
   202
   203          // Verify the manifest contents
   204          for p, hash := range manifest.Files {
   205                  err = verifyHash(s.log, plugin, p, hash)
   206                  if err != nil {
   207                          s.log.Debug("Plugin signature invalid", "pluginId", plugin.JSONData.ID, "error", err)
   208                          return plugins.Signature{
   209                                  Status: plugins.SignatureStatusModified,
   210                          }, nil
   211                  }
   212
   213                  manifestFiles[p] = struct{}{}
   214          }
   215
   216          // Track files missing from the manifest
   217          var unsignedFiles []string
   218          for _, f := range fsFiles {
   219                  // Ensure slashes are used, because MANIFEST.txt always uses slashes regardless of the filesystem
   220                  f = toSlash(f)
   221
   222                  // Ignoring unsigned Chromium debug.log so it doesn't invalidate the signature for Renderer plugin running on Windows
   223                  if runningWindows && plugin.JSONData.Type == plugins.TypeRenderer && filepath.Base(f) == "debug.log" {
   224                          continue
   225                  }
   226
   227                  if f == "MANIFEST.txt" {
   228                          continue
   229                  }
   230                  if _, exists := manifestFiles[f]; !exists {
   231                          unsignedFiles = append(unsignedFiles, f)
   232                  }
   233          }
   234
   235          if len(unsignedFiles) > 0 {
   236                  s.log.Warn("The following files were not included in the signature", "plugin", plugin.JSONData.ID, "files", unsignedFiles)
   237                  return plugins.Signature{
   238                          Status: plugins.SignatureStatusModified,
   239                  }, nil
   240          }
   241
   242          s.log.Debug("Plugin signature valid", "id", plugin.JSONData.ID)
   243          return plugins.Signature{
   244                  Status:     plugins.SignatureStatusValid,
   245                  Type:       manifest.SignatureType,
   246                  SigningOrg: manifest.SignedByOrgName,
   247          }, nil
   248  }
   249
   250  func verifyHash(mlog log.Logger, plugin plugins.FoundPlugin, path, hash string) error {
   251          path = fromSlash(path)
   252
   253          // nolint:gosec
   254          // We can ignore the gosec G304 warning on this one because `path` is based
   255          // on the path provided in a manifest file for a plugin and not user input.
   256          f, err := plugin.FS.Open(path)
   257          if err != nil {
   258                  if os.IsPermission(err) {
   259                          mlog.Warn("Could not open plugin file due to lack of permissions", "plugin", plugin.JSONData.ID, "path", path)
   260                          return errors.New("permission denied when attempting to read plugin file")
   261                  }
   262                  mlog.Warn("Plugin file listed in the manifest was not found", "plugin", plugin.JSONData.ID, "path", path)
   263                  return errors.New("plugin file listed in the manifest was not found")
   264          }
   265          defer func() {
   266                  if err := f.Close(); err != nil {
   267                          mlog.Warn("Failed to close plugin file", "path", path, "error", err)
   268                  }
   269          }()
   270
   271          h := sha256.New()
   272          if _, err := io.Copy(h, f); err != nil {
   273                  return fmt.Errorf("could not calculate plugin file checksum. Path: %s. Error: %w", path, err)
   274          }
   275          sum := hex.EncodeToString(h.Sum(nil))
   276          if sum != hash {
   277                  mlog.Warn("Plugin file checksum does not match signature checksum", "plugin", plugin.JSONData.ID, "path", path)
   278                  return errors.New("plugin file checksum does not match signature checksum")
   279          }
   280
   281          return nil
   282  }
