   316  type invalidFieldErr struct {
   317          field string
   318  }
   319
   320  func (r invalidFieldErr) Error() string {
   321          return fmt.Sprintf("valid manifest field %s is required", r.field)
   322  }
   323
   324  func (s *Signature) validateManifest(ctx context.Context, m PluginManifest, block *clearsign.Block) error {
   325          if len(m.Plugin) == 0 {
   326                  return invalidFieldErr{field: "plugin"}
   327          }
   328          if len(m.Version) == 0 {
   329                  return invalidFieldErr{field: "version"}
   330          }
   331          if len(m.KeyID) == 0 {
   332                  return invalidFieldErr{field: "keyId"}
   333          }
   334          if m.Time == 0 {
   335                  return invalidFieldErr{field: "time"}
   336          }
   337          if len(m.Files) == 0 {
   338                  return invalidFieldErr{field: "files"}
   339          }
   340          if m.IsV2() {
   341                  if len(m.SignedByOrg) == 0 {
   342                          return invalidFieldErr{field: "signedByOrg"}
   343                  }
   344                  if len(m.SignedByOrgName) == 0 {
   345                          return invalidFieldErr{field: "signedByOrgName"}
   346                  }
   347                  if !m.SignatureType.IsValid() {
   348                          return fmt.Errorf("%s is not a valid signature type", m.SignatureType)
   349                  }
   350          }
   351
   352          return s.Verify(ctx, m.KeyID, block)
   353  }
   354
   355  func (s *Signature) Verify(ctx context.Context, keyID string, block *clearsign.Block) error {
   356          publicKey, err := s.kr.GetPublicKey(ctx, keyID)
   357          if err != nil {
   358                  return err
   359          }
   360
   361          keyring, err := openpgp.ReadArmoredKeyRing(bytes.NewBufferString(publicKey))
   362          if err != nil {
   363                  return fmt.Errorf("%v: %w", "failed to parse public key", err)
   364          }
   365
   366          if _, err = openpgp.CheckDetachedSignature(keyring,
   367                  bytes.NewBuffer(block.Bytes),
   368                  block.ArmoredSignature.Body, &packet.Config{}); err != nil {
   369                  return fmt.Errorf("failed to check signature: %w", err)
   370          }
   371
   372          return nil
   373  }

