    48  // Construct will calculate the plugin's signature state and create the plugin using the pluginFactoryFunc.
    49  func (c *DefaultConstructor) Construct(ctx context.Context, src plugins.PluginSource, bundle *plugins.FoundBundle) ([]*plugins.Plugin, error) {
    50          sig, err := c.signatureCalculator.Calculate(ctx, src, bundle.Primary)
    51          if err != nil {
    52                  c.log.Warn("Could not calculate plugin signature state", "pluginId", bundle.Primary.JSONData.ID, "error", err)
    53                  return nil, err
    54          }
    55          plugin, err := c.pluginFactoryFunc(bundle, src.PluginClass(ctx), sig)
    56          if err != nil {
    57                  c.log.Error("Could not create primary plugin base", "pluginId", bundle.Primary.JSONData.ID, "error", err)
    58                  return nil, err
    59          }
    60          res := make([]*plugins.Plugin, 0, len(plugin.Children)+1)
    61          res = append(res, plugin)
    62          res = append(res, plugin.Children...)
    63          return res, nil
    64  }
