   116  // AppChildDecorateFunc is a DecorateFunc that configures child plugins of app plugins.
   117  func AppChildDecorateFunc() DecorateFunc {
   118          return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
   119                  if p.Parent != nil && p.Parent.IsApp() {
   120                          configureAppChildPlugin(p.Parent, p)
   121                  }
   122                  return p, nil
   123          }
