    21  const publicKeySyncInterval = 10 * 24 * time.Hour // 10 days
    22
    23  // ManifestKeys is the database representation of public keys
    24  // used to verify plugin manifests.
    25  type ManifestKeys struct {
    26          KeyID     string `json:"keyId"`
    27          PublicKey string `json:"public"`
    28          Since     int64  `json:"since"`
    29  }
    30
    31  type KeyRetriever struct {
    32          cfg *setting.Cfg
