    43  func ProvideService(cfg *setting.Cfg, kv plugins.KeyStore) *KeyRetriever {
    44          kr := &KeyRetriever{
    45                  cfg: cfg,
    46                  log: log.New("plugin.signature.key_retriever"),
    47                  cli: makeHttpClient(),
    48                  kv:  kv,
    49          }
    50          return kr
    51  }
