    53  // IsDisabled disables dynamic retrieval of public keys from the API server.
    54  func (kr *KeyRetriever) IsDisabled() bool {
    55          return kr.cfg.PluginSkipPublicKeyDownload
    56  }
    57
    58  func (kr *KeyRetriever) Run(ctx context.Context) error {
    59          // do an initial update if necessary
    60          err := kr.updateKeys(ctx)
    61          if err != nil {
    62                  kr.log.Error("Error downloading plugin manifest keys", "error", err)
    63          }
    64
    65          // calculate initial send delay
    66          lastUpdated, err := kr.kv.GetLastUpdated(ctx)
    67          if err != nil {
    68                  return err
    69          }
    70          nextSendInterval := time.Until(lastUpdated.Add(publicKeySyncInterval))
    71          if nextSendInterval < time.Minute {
    72                  nextSendInterval = time.Minute
    73          }
    74
    75          downloadKeysTicker := time.NewTicker(nextSendInterval)
    76          defer downloadKeysTicker.Stop()
    77
    78          select {
    79          case <-downloadKeysTicker.C:
    80                  err = kr.updateKeys(ctx)
    81                  if err != nil {
    82                          kr.log.Error("Error downloading plugin manifest keys", "error", err)
    83                  }
    84
    85                  if nextSendInterval != publicKeySyncInterval {
    86                          nextSendInterval = publicKeySyncInterval
    87                          downloadKeysTicker.Reset(nextSendInterval)
    88                  }
    89          case <-ctx.Done():
    90                  return ctx.Err()
    91          }
    92
    93          return ctx.Err()
    94  }
    95
    96  func (kr *KeyRetriever) updateKeys(ctx context.Context) error {
    97          kr.lock.Lock()
    98          defer kr.lock.Unlock()
    99
   100          lastUpdated, err := kr.kv.GetLastUpdated(ctx)
   101          if err != nil {
   102                  return err
   103          }
   104          if !kr.cfg.PluginForcePublicKeyDownload && time.Since(lastUpdated) < publicKeySyncInterval {
   105                  // Cache is still valid
   106                  return nil
   107          }
   108
   109          return kr.downloadKeys(ctx)
   110  }
   111
   112  // Retrieve the key from the API and store it in the database
   113  func (kr *KeyRetriever) downloadKeys(ctx context.Context) error {
   114          var data struct {
   115                  Items []ManifestKeys
   116          }
   117
   118          url, err := url.JoinPath(kr.cfg.GrafanaComAPIURL, "/plugins/ci/keys") // nolint:gosec URL is provided by config
   119          if err != nil {
   120                  return err
   121          }
   122          req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
   123          if err != nil {
   124                  return err
   125          }
   126
   127          resp, err := kr.cli.Do(req)
   128          if err != nil {
   129                  return err
   130          }
   131          defer func() {
   132                  err := resp.Body.Close()
   133                  if err != nil {
   134                          kr.log.Warn("Error closing response body", "error", err)
   135                  }
   136          }()
   137
   138          if resp.StatusCode != http.StatusOK {
   139                  return fmt.Errorf("unexpected status code: %d", resp.StatusCode)
   140          }
   141
   142          body, err := io.ReadAll(resp.Body)
   143          if err != nil {
   144                  return err
   145          }
   146
   147          if err := json.Unmarshal(body, &data); err != nil {
   148                  kr.log.Debug("Error unmarshalling response body", "error", err, "body", string(body))
   149                  return fmt.Errorf("error unmarshalling response body: %w", err)
   150          }
   151
   152          if len(data.Items) == 0 {
   153                  return errors.New("missing public key")
   154          }
   155
   156          cachedKeys, err := kr.kv.ListKeys(ctx)
   157          if err != nil {
   158                  return err
   159          }
   160
   161          shouldKeep := make(map[string]bool)
   162          for _, key := range data.Items {
   163                  err = kr.kv.Set(ctx, key.KeyID, key.PublicKey)
   164                  if err != nil {
   165                          return err
   166                  }
   167                  shouldKeep[key.KeyID] = true
   168          }
   169
   170          // Delete keys that are no longer in the API
   171          for _, key := range cachedKeys {
   172                  if !shouldKeep[key] {
   173                          err = kr.kv.Delete(ctx, key)
   174                          if err != nil {
   175                                  return err
   176                          }
   177                  }
   178          }
   179          return nil
   180  }
   181
   182  func (kr *KeyRetriever) ensureKeys(ctx context.Context) error {
   183          if kr.hasKeys {
   184                  return nil
   185          }
   186          keys, err := kr.kv.ListKeys(ctx)
   187          if err != nil {
   188                  return err
   189          }
   190          if len(keys) == 0 {
   191                  // Populate with the default key
   192                  err := kr.kv.Set(ctx, statickey.GetDefaultKeyID(), statickey.GetDefaultKey())
   193                  if err != nil {
   194                          return err
   195                  }
   196          }
   197          kr.hasKeys = true
   198          return nil
   199  }
   200
   201  // GetPublicKey loads public keys from:
   202  //   - The hard-coded value if the feature flag is not enabled.
   203  //   - A cached value from kv storage if it has been already retrieved. This cache is populated from the grafana.com API.
   204  func (kr *KeyRetriever) GetPublicKey(ctx context.Context, keyID string) (string, error) {
   205          kr.lock.Lock()
   206          defer kr.lock.Unlock()
   207
   208          err := kr.ensureKeys(ctx)
   209          if err != nil {
   210                  return "", err
   211          }
   212
   213          key, exist, err := kr.kv.Get(ctx, keyID)
   214          if err != nil {
   215                  return "", err
   216          }
   217          if exist {
   218                  return key, nil
   219          }
   220
   221          return "", fmt.Errorf("missing public key for %s", keyID)
   222  }
