   224  // Same configuration as pkg/plugins/repo/client.go
   225  func makeHttpClient() http.Client {
   226          tr := &http.Transport{
   227                  Proxy: http.ProxyFromEnvironment,
   228                  DialContext: (&net.Dialer{
   229                          Timeout:   30 * time.Second,
   230                          KeepAlive: 30 * time.Second,
   231                  }).DialContext,
   232                  MaxIdleConns:          100,
   233                  IdleConnTimeout:       90 * time.Second,
   234                  TLSHandshakeTimeout:   10 * time.Second,
   235                  ExpectContinueTimeout: 1 * time.Second,
   236          }
   237
   238          return http.Client{
   239                  Timeout:   10 * time.Second,
   240                  Transport: tr,
   241          }
   242  }

