    46  func (cfg *Cfg) migrateInstallPluginsToPreinstallPluginsSync(rawInstallPlugins, installPluginsForce string, preinstallPluginsSync map[string]InstallPlugin) {
    47          if strings.ToLower(installPluginsForce) == "true" || rawInstallPlugins == "" {
    48                  cfg.Logger.Debug("GF_INSTALL_PLUGINS_FORCE is set to true, skipping migration of GF_INSTALL_PLUGINS to GF_PLUGINS_PREINSTALL_SYNC")
    49                  return
    50          }
    51          installPluginsEntries := strings.Split(rawInstallPlugins, ",")
    52
    53          // Format 1: ID only (e.g., "grafana-clock-panel")
    54          // Format 2: ID with version (e.g., "grafana-clock-panel 1.0.1")
    55          // Format 3: URL with folder (e.g., "https://grafana.com/api/plugins/grafana-clock-panel/versions/latest/download;grafana-clock-panel")
    56          pluginRegex := regexp.MustCompile(`(?:([^;]+);)?([^;\s]+)(?:\s+(.+))?`)
    57          for _, entry := range installPluginsEntries {
    58                  trimmedEntry := strings.TrimSpace(entry)
    59                  if trimmedEntry == "" {
    60                          continue
    61                  }
    62
    63                  matches := pluginRegex.FindStringSubmatch(trimmedEntry)
    64
    65                  if matches == nil {
    66                          cfg.Logger.Debug("No match found for entry: ", trimmedEntry)
    67                          continue
    68                  }
    69
    70                  url := ""
    71                  if len(matches) > 1 {
    72                          url = strings.TrimSpace(matches[1])
    73                  }
    74
    75                  id := ""
    76                  if len(matches) > 2 {
    77                          id = strings.TrimSpace(matches[2])
    78                  }
    79                  if _, exists := preinstallPluginsSync[id]; exists {
    80                          continue
    81                  }
    82
    83                  version := ""
    84                  if len(matches) > 3 {
    85                          version = strings.TrimSpace(matches[3])
    86                  }
    87                  if id != "" {
    88                          preinstallPluginsSync[id] = InstallPlugin{ID: id, Version: version, URL: url}
    89                  } else {
    90                          cfg.Logger.Debug("No ID found for entry: ", trimmedEntry, "matches: ", matches)
    91                  }
    92          }
    93  }
