   133  func (cfg *Cfg) readPluginSettings(iniFile *ini.File) error {
   134          pluginsSection := iniFile.Section("plugins")
   135
   136          cfg.PluginsEnableAlpha = pluginsSection.Key("enable_alpha").MustBool(false)
   137          cfg.PluginsAppsSkipVerifyTLS = pluginsSection.Key("app_tls_skip_verify_insecure").MustBool(false)
   138          cfg.PluginSettings = extractPluginSettings(iniFile.Sections())
   139          cfg.PluginSkipPublicKeyDownload = pluginsSection.Key("public_key_retrieval_disabled").MustBool(false)
   140          cfg.PluginForcePublicKeyDownload = pluginsSection.Key("public_key_retrieval_on_startup").MustBool(false)
   141
   142          cfg.PluginsAllowUnsigned = util.SplitString(pluginsSection.Key("allow_loading_unsigned_plugins").MustString(""))
   143          cfg.DisablePlugins = util.SplitString(pluginsSection.Key("disable_plugins").MustString(""))
   144          cfg.ForwardHostEnvVars = util.SplitString(pluginsSection.Key("forward_host_env_vars").MustString(""))
   145          disablePreinstall := pluginsSection.Key("preinstall_disabled").MustBool(false)
   146          if !disablePreinstall {
   147                  rawInstallPluginsAsync := util.SplitString(pluginsSection.Key("preinstall").MustString(""))
   148                  preinstallPluginsAsync := make(map[string]InstallPlugin)
   149                  // Add the default preinstalled plugins to pre install plugins async list
   150                  for _, plugin := range defaultPreinstallPlugins {
   151                          preinstallPluginsAsync[plugin.ID] = plugin
   152                  }
   153                  if cfg.IsFeatureToggleEnabled("grafanaAdvisor") { // Use literal string to avoid circular dependency
   154                          preinstallPluginsAsync["grafana-advisor-app"] = InstallPlugin{"grafana-advisor-app", "", ""}
   155                  }
   156                  if cfg.IsFeatureToggleEnabled("grafanaPathfinder") { // Use literal string to avoid circular dependency
   157                          preinstallPluginsAsync["grafana-pathfinder-app"] = InstallPlugin{"grafana-pathfinder-app", "", ""}
   158                  }
   159                  cfg.processPreinstallPlugins(rawInstallPluginsAsync, preinstallPluginsAsync)
   160
   161                  rawInstallPluginsSync := util.SplitString(pluginsSection.Key("preinstall_sync").MustString(""))
   162                  preinstallPluginsSync := make(map[string]InstallPlugin)
   163                  cfg.processPreinstallPlugins(rawInstallPluginsSync, preinstallPluginsSync)
   164                  cfg.migrateInstallPluginsToPreinstallPluginsSync(os.Getenv("GF_INSTALL_PLUGINS"), os.Getenv("GF_INSTALL_PLUGINS_FORCE"), preinstallPluginsSync)
   165                  // Remove from the list the plugins that have been disabled
   166                  for _, disabledPlugin := range cfg.DisablePlugins {
   167                          delete(preinstallPluginsAsync, disabledPlugin)
   168                          delete(preinstallPluginsSync, disabledPlugin)
   169                  }
   170                  for _, plugin := range preinstallPluginsSync {
   171                          cfg.PreinstallPluginsSync = append(cfg.PreinstallPluginsSync, plugin)
   172                          // preinstallSync plugin has priority over preinstallAsync
   173                          delete(preinstallPluginsAsync, plugin.ID)
   174                  }
   175                  for _, plugin := range preinstallPluginsAsync {
   176                          cfg.PreinstallPluginsAsync = append(cfg.PreinstallPluginsAsync, plugin)
   177                  }
   178
   179                  installPluginsInAsync := pluginsSection.Key("preinstall_async").MustBool(true)
   180                  if !installPluginsInAsync {
   181                          for key, plugin := range preinstallPluginsAsync {
   182                                  if _, exists := preinstallPluginsSync[key]; !exists {
   183                                          cfg.PreinstallPluginsSync = append(cfg.PreinstallPluginsSync, plugin)
   184                                  }
   185                          }
   186                          cfg.PreinstallPluginsAsync = nil
   187                  }
   188          }
   189
   190          cfg.PluginCatalogURL = pluginsSection.Key("plugin_catalog_url").MustString("https://grafana.com/grafana/plugins/")
   191          cfg.PluginAdminEnabled = pluginsSection.Key("plugin_admin_enabled").MustBool(true)
   192          cfg.PluginAdminExternalManageEnabled = pluginsSection.Key("plugin_admin_external_manage_enabled").MustBool(false)
   193          cfg.PluginCatalogHiddenPlugins = util.SplitString(pluginsSection.Key("plugin_catalog_hidden_plugins").MustString(""))
   194
   195          // Pull disabled plugins from the catalog
   196          cfg.PluginCatalogHiddenPlugins = append(cfg.PluginCatalogHiddenPlugins, cfg.DisablePlugins...)
   197
   198          // Plugins CDN settings
   199          cfg.PluginsCDNURLTemplate = strings.TrimRight(pluginsSection.Key("cdn_base_url").MustString(""), "/")
   200          cfg.PluginLogBackendRequests = pluginsSection.Key("log_backend_requests").MustBool(false)
   201
   202          cfg.PluginUpdateStrategy = pluginsSection.Key("update_strategy").In(PluginUpdateStrategyLatest, []string{PluginUpdateStrategyLatest, PluginUpdateStrategyMinor})
   203
   204          // Plugin API restrictions - read from sections
   205          cfg.PluginRestrictedAPIsAllowList = readPluginAPIRestrictionsSection(iniFile, "plugins.restricted_apis_allowlist")
   206          cfg.PluginRestrictedAPIsBlockList = readPluginAPIRestrictionsSection(iniFile, "plugins.restricted_apis_blocklist")
   207
   208          return nil
   209  }

