    15  // CacheKvStore is a Store that stores data in a *kvstore.NamespacedKVStore.
    16  // It also stores a last updated time, which is unique for all the keys and is updated on each call to `Set`,
    17  // and can be used to determine if the data is stale.
    18  type CacheKvStore struct {
